// Only run on the actual last day of the month
const now = new Date();
const tomorrow = new Date(now);
tomorrow.setDate(tomorrow.getDate() + 1);
const isLastDay = tomorrow.getMonth() !== now.getMonth();
return [{ json: { isLastDay, date: now.toISOString() } }];

const d = $input.first().json;
const month = new Date().toLocaleDateString('en-MY', { month: 'long', year: 'numeric' });

const groceryRows = (d.groceryReceipts ?? []).map(r =>
  `<tr><td>${r.store}</td><td>${r.date}</td><td style='text-align:right'>RM ${r.total.toFixed(2)}</td></tr>`
).join('');

const medicalRows = (d.medicalReceipts ?? []).map(r =>
  `<tr><td>${r.hospital}</td><td>${r.date}</td><td style='text-align:right'>RM ${r.total.toFixed(2)}</td></tr>`
).join('');

const html = `
<html><body style='font-family:Arial,sans-serif;color:#222;max-width:600px;margin:auto'>
<h2 style='color:#059669'>KAI Monthly Care Expense Report</h2>
<p style='color:#666'>${month}</p>

<div style='background:#f0fdf4;border:1px solid #bbf7d0;border-radius:8px;padding:16px;margin:16px 0'>
  <strong>Total Spending: RM ${d.grandTotal.toFixed(2)}</strong><br/>
  Groceries: RM ${d.groceryTotal.toFixed(2)} &nbsp;|&nbsp; Medical: RM ${d.medicalTotal.toFixed(2)}
</div>

${groceryRows ? `<h3>🛒 Grocery Expenses</h3>
<table width='100%' style='border-collapse:collapse'>
<tr style='background:#f3f4f6'><th style='padding:8px;text-align:left'>Store</th><th>Date</th><th>Amount</th></tr>
${groceryRows}
</table>` : ''}

${medicalRows ? `<h3>🏥 Medical Expenses</h3>
<table width='100%' style='border-collapse:collapse'>
<tr style='background:#f3f4f6'><th style='padding:8px;text-align:left'>Hospital</th><th>Date</th><th>Amount</th></tr>
${medicalRows}
</table>` : ''}

<p style='color:#999;font-size:12px;margin-top:24px'>Generated automatically by KAI &middot; ${new Date().toLocaleDateString('en-MY')}</p>
</body></html>`;

const subject = `KAI Care Expenses — ${month} — RM ${d.grandTotal.toFixed(2)}`;
return [{ json: { html, subject, grandTotal: d.grandTotal } }];

